import { FileNode } from "../lib/types";

interface SidebarProps {
  tree: FileNode[];
  selectedPath: string | null;
  onSelect: (node: FileNode) => void;
  onOpenWorkspace: () => void;
  workspaceName: string | null;
}

interface FileItemProps {
  node: FileNode;
  depth: number;
  selectedPath: string | null;
  onSelect: (node: FileNode) => void;
}

function FileItem({ node, depth, selectedPath, onSelect }: FileItemProps) {
  const isSelected = node.path === selectedPath;
  const isMarkdown = node.extension === ".md" || node.extension === ".mdx";

  if (node.isDirectory) {
    return (
      <div>
        <div
          className="sidebar-dir"
          style={{ paddingLeft: `${12 + depth * 14}px` }}
        >
          <span className="sidebar-icon">Ō¢Ė</span>
          {node.name}
        </div>
        {node.children?.map((child) => (
          <FileItem
            key={child.path}
            node={child}
            depth={depth + 1}
            selectedPath={selectedPath}
            onSelect={onSelect}
          />
        ))}
      </div>
    );
  }

  if (!isMarkdown) return null;

  return (
    <div
      className={`sidebar-file ${isSelected ? "selected" : ""}`}
      style={{ paddingLeft: `${12 + depth * 14}px` }}
      onClick={() => onSelect(node)}
    >
      <span className="sidebar-icon">ŌŚ”</span>
      {node.name.replace(/\.mdx?$/, "")}
    </div>
  );
}

export function Sidebar({
  tree,
  selectedPath,
  onSelect,
  onOpenWorkspace,
  workspaceName,
}: SidebarProps) {
  return (
    <div className="sidebar">
      <div className="sidebar-header">
        <span className="sidebar-workspace-name">
          {workspaceName ?? "No workspace"}
        </span>
        <button className="sidebar-open-btn" onClick={onOpenWorkspace} title="Open workspace">
          ŌŖĢ
        </button>
      </div>

      <div className="sidebar-tree">
        {tree.length === 0 ? (
          <div className="sidebar-empty">
            <p>No workspace open.</p>
            <button className="sidebar-open-workspace-btn" onClick={onOpenWorkspace}>
              Open folder
            </button>
          </div>
        ) : (
          tree.map((node) => (
            <FileItem
              key={node.path}
              node={node}
              depth={0}
              selectedPath={selectedPath}
              onSelect={onSelect}
            />
          ))
        )}
      </div>
    </div>
  );
}

// Learn more about Tauri commands at https://tauri.app/develop/calling-rust/
#[tauri::command]
fn greet(name: &str) -> String {
    format!("Hello, {}! You've been greeted from Rust!", name)
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_opener::init())
        .invoke_handler(tauri::generate_handler![greet])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

